"all suspended users\",\n  // \"all providers\", etc.\n  @@index([role])\n  @@index([status])\n  @@map(\"users\")\n}\n\nmodel Category {\n  id          String   @id @default(uuid())\n  name        String   @unique\n  description String?\n  createdAt   DateTime @default(now())\n  updatedAt   DateTime @updatedAt\n\n  gearItems Gear[]\n\n  @@map(\"categories\")\n}\n\nmodel Gear {\n  id            String   @id @default(uuid())\n  title         String\n  description   String\n  brand         String?\n  pricePerDay   Decimal  @db.Decimal(10, 2)\n  stock         Int      @default(1)\n  isAvailable   Boolean  @default(true)\n  images        String[]\n  averageRating Float    @default(0)\n  reviewCount   Int      @default(0)\n  // Denormalized on purpose: Prisma can't ORDER BY an aggregate across a\n  // relation efficiently at scale. These two columns are recalculated by\n  // the Reviews module every time a review is created/updated/deleted,\n  // so \"sort by rating\" is a plain indexed column read, not a per-request\n  // aggregation over every review row.\n  createdAt     DateTime @default(now())\n  updatedAt     DateTime @updatedAt\n\n  categoryId String\n  category   Category @relation(fields: [categoryId], references: [id], onDelete: Restrict)\n  // Restrict (not Cascade): deleting a category that still has gear under\n  // it should fail loudly, forcing an admin to reassign or remove the\n  // gear first, rather than silently orphaning or nuking listings.\n\n  providerId String\n  provider   User   @relation(\"ProviderGear\", fields: [providerId], references: [id], onDelete: Cascade)\n  // Cascade: if a provider account is deleted outright, their listings\n  // don't make sense to keep around. In practice most platforms prefer\n  // suspending providers instead of hard-deleting them, but this is the\n  // safe default if a hard delete does happen.\n\n  rentalOrders RentalOrder[]\n  reviews      Review[]\n\n  // Supports the \"browse/filter gear\" endpoints: by category, by\n  // provider's own inventory view, by availability, and price-range\n  // filtering/sorting.\n  @@index([categoryId])\n  @@index([providerId])\n  @@index([isAvailable])\n  @@index([pricePerDay])\n  @@index([averageRating])\n  @@index([brand])\n  @@map(\"gear_items\")\n}\n\nmodel RentalOrder {\n  id          String       @id @default(uuid())\n  quantity    Int          @default(1)\n  startDate   DateTime\n  endDate     DateTime\n  totalDays   Int\n  // Computed once at creation from (endDate - startDate), rounded up to a\n  // whole day. Persisted rather than derived on every read so order\n  // history stays stable and cheap to query/sort.\n  pricePerDay Decimal      @db.Decimal(10, 2)\n  // Snapshotted from Gear.pricePerDay at order creation time, so a later\n  // price change by the provider never rewrites historical order totals.\n  totalAmount Decimal      @db.Decimal(10, 2)\n  status      RentalStatus @default(PLACED)\n  createdAt   DateTime     @default(now())\n  updatedAt   DateTime     @updatedAt\n\n  customerId String\n  customer   User   @relation(\"CustomerRentals\", fields: [customerId], references: [id], onDelete: Restrict)\n  // Restrict: rental history is financial/audit data. A customer account\n  // should be suspended, never hard-deleted, while orders reference it.\n\n  gearId String\n  gear   Gear   @relation(fields: [gearId], references: [id], onDelete: Restrict)\n  // Restrict: same reasoning — historical orders must keep pointing at a\n  // real gear record for auditing, even if that gear is later marked\n  // unavailable.\n\n  payment Payment?\n  review  Review?\n\n  @@index([customerId])\n  @@index([gearId])\n  @@index([status])\n  @@index([startDate, endDate])\n  @@map(\"rental_orders\")\n}\n\nmodel Payment {\n  id            String        @id @default(uuid())\n  transactionId String        @unique\n  amount        Decimal       @db.Decimal(10, 2)\n  method        PaymentMethod\n  status        PaymentStatus @default(PENDING)\n  paidAt        DateTime?\n  rawResponse   Json?\n  createdAt     DateTime      @default(now())\n  updatedAt     DateTime      @updatedAt\n\n  rentalOrderId String      @unique\n  rentalOrder   RentalOrder @relation(fields: [rentalOrderId], references: [id], onDelete: Cascade)\n  // Cascade: a Payment record has no independent meaning without its\n  // order — if the order is ever purged, its payment record should go\n  // with it (in practice orders are never hard-deleted, only cancelled).\n\n  @@index([status])\n  @@map(\"payments\")\n}\n\nmodel Review {\n  id        String   @id @default(uuid())\n  rating    Int\n  comment   String?\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  customerId String\n  customer   User   @relation(fields: [customerId], references: [id], onDelete: Cascade)\n\n  gearId String\n  gear   Gear   @relation(fields: [gearId], references: [id], onDelete: Cascade)\n  // Cascade on both: a review is meaningless without the customer or the\n  // gear it's attached to, unlike Payment/RentalOrder which are financial\n  // records worth preserving.\n\n  rentalOrderId String?      @unique\n  rentalOrder   RentalOrder? @relation(fields: [rentalOrderId], references: [id], onDelete: SetNull)\n  // Links the review back to the specific order it came from, so the\n  // service layer can enforce \"only after RETURNED\". SetNull rather than\n  // Cascade/Restrict: if the order is ever removed, the review can stand\n  // on its own as historical feedback rather than being deleted too.\n\n  // One review per customer per gear item — prevents review spam even\n  // across multiple separate orders of the same item.\n  @@unique([customerId, gearId])\n  @@index([gearId])\n  @@map(\"reviews\")\n}\n",
